('badminton', 'Modern Origins', 'In which country were the modern rules of badminton first standardized?', 'multiple_choice', '["India", "China", "England", "Malaysia"]', 'England', 'The modern game was standardized at Badminton House, the estate of the Duke of Beaufort in Gloucestershire.'),
('badminton', 'Shuttlecock Feathers', 'A professional feather shuttlecock is traditionally made from the feathers of which wing of a goose?', 'multiple_choice', '["Right wing", "Left wing", "Both wings", "Tail feathers"]', 'Left wing', 'Feathers from the left wing are used to ensure the shuttlecock spins clockwise for stability.'),
('badminton', 'Olympic Debut', 'In which year did badminton become an official medal sport at the Olympic Games?', 'text', NULL, '1992', 'Badminton made its official debut at the 1992 Barcelona Olympics.'),
('badminton', 'Fastest Smash', 'The fastest recorded smash in professional badminton exceeds 500 km/h.', 'boolean', NULL, 'True', 'Satwiksairaj Rankireddy set a world record with a smash speed of 565 km/h in 2023.'),
('badminton', 'Service Height', 'What is the fixed height limit (in meters) for a legal serve in professional play?', 'text', NULL, '1.15', 'According to BWF rules, the entire shuttle must be below 1.15 meters at the point of impact.'),
('badminton', 'Thomas Cup', 'The Thomas Cup is the world team championship for which category?', 'multiple_choice', '["Women", "Mixed", "Men", "Juniors"]', 'Men', 'The Thomas Cup was donated by Sir George Thomas for the international men''s team competition.'),
('badminton', 'Scoring Ceiling', 'What is the absolute maximum score a single game can reach?', 'text', NULL, '30', 'If a game reaches 29-29, the first player to 30 points wins the game.'),
('badminton', 'Court Lines', 'In badminton, a shuttle landing on the boundary line is considered "out".', 'boolean', NULL, 'False', 'The lines are part of the court area; if any part of the shuttle touches the line, it is "in".'),
('badminton', 'Lee Chong Wei', 'Which country does the legendary player Lee Chong Wei represent?', 'text', NULL, 'Malaysia', 'Lee Chong Wei is a former world number one and a three-time Olympic silver medalist for Malaysia.'),
('badminton', 'Mixed Doubles', 'In mixed doubles, the female player typically spends most of her time at the back of the court.', 'boolean', NULL, 'False', 'Traditionally, the female player plays at the net to intercept shots while the male player covers the back.'),
('mobile legends', 'Hero Titles', 'Which hero is known as the "Son of the Dragon"?', 'text', NULL, 'Zilong', 'Zilong is one of the original heroes and is the loyal disciple of the Great Dragon.'),
('mobile legends', 'Item Passive', 'Which item provides a passive called "Resurrect" to come back to life after death?', 'multiple_choice', '["Blade of Despair", "Immortal", "Winter Truncheon", "Athena''s Shield"]', 'Immortal', 'Immortality allows a hero to resurrect 2.5 seconds after death with a small shield.'),
('mobile legends', 'Laning Phase', 'Which lane is typically reserved for the "Marksman" role?', 'multiple_choice', '["Exp Lane", "Mid Lane", "Gold Lane", "Jungle"]', 'Gold Lane', 'The Gold Lane provides extra gold from siege minions, allowing Marksmen to buy items faster.'),
('mobile legends', 'Max Level', 'What is the maximum level a hero can reach in a standard match?', 'text', NULL, '15', 'Heroes cap out at level 15, which maximizes their skill points and base attributes.'),
('mobile legends', 'Retribution Spell', 'The Retribution battle spell is mandatory for the Jungler role.', 'boolean', NULL, 'True', 'Retribution is required to purchase Jungle equipment and effectively secure the Turtle and Lord.'),
('mobile legends', 'Lord Spawn', 'The Lord appears for the first time in the river at which minute mark?', 'text', NULL, '8', 'The Lord replaces the Turtle pit at exactly 8:00 minutes into the game.'),
('mobile legends', 'Hero Roles', 'Which hero can "possess" an ally to provide a massive shield?', 'text', NULL, 'Angela', 'Angela''s ultimate, Heartgard, allows her to attach to an ally and provide support from within.'),
('mobile legends', 'Draft Pick', 'In Epic rank and above, each team can ban up to how many heroes?', 'text', NULL, '5', 'The standard tournament and high-rank draft allow for a total of 10 bans (5 per team).'),
('mobile legends', 'True Damage', 'True damage ignores all physical and magic defense stats.', 'boolean', NULL, 'True', 'True damage bypasses all forms of defense, dealing its full value directly to the enemy HP.'),
('mobile legends', 'Map Name', 'What is the official name of the map used for 5v5 Rank matches?', 'text', NULL, 'The Land of Dawn', 'All standard competitive matches in MLBB take place in the Land of Dawn.'),
('badminton', 'Net Height', 'What is the height of the net at the center of the court?', 'multiple_choice', '["1.55m", "1.524m", "1.60m", "1.50m"]', '1.524m', 'The net is exactly 5 feet (1.524m) high at the center, though it is 1.55m at the posts.'),
('mobile legends', 'Hero Skills', 'Which hero uses "Cables" to swing between walls for high mobility?', 'text', NULL, 'Fanny', 'Fanny is famous for her "Steel Cable" skill, which makes her one of the hardest heroes to master.'),
('badminton', 'Strings', 'Higher string tension provides more power but less control.', 'boolean', NULL, 'False', 'Higher tension provides more control and "feel," while lower tension provides a "trampoline effect" for more power.'),
('mobile legends', 'Active Items', 'Which item makes the user immune to physical damage for a short duration?', 'multiple_choice', '["Windtalker", "Wind of Nature", "Golden Staff", "Rose Gold Meteor"]', 'Wind of Nature', 'Commonly known as "WON," it provides physical immunity, making it core for Marksmen.'),
('badminton', 'Shots', 'A "Clear" is a shot hit deep into the opponent''s backcourt.', 'boolean', NULL, 'True', 'The clear is used to push the opponent away from the net and reset the rally.'),
('mobile legends', 'Lore', 'Gusion is the brother of which other hero?', 'text', NULL, 'Aamon', 'Both are members of the House of Paxley, with Aamon being the elder brother.'),
('badminton', 'Grip Sizing', 'In the Yonex sizing system, is G5 larger or smaller than G4?', 'multiple_choice', '["Larger", "Smaller", "Same Size", "Depends on country"]', 'Smaller', 'In badminton handle sizing, a higher number indicates a smaller circumference.'),
('mobile legends', 'Rank Tiers', 'Which rank tier sits immediately below Mythic?', 'text', NULL, 'Legend', 'Players must progress through Legend I to V before reaching the Mythic rank.'),
('badminton', 'Scoring Interval', 'At what score do players have a 60-second break (interval)?', 'text', NULL, '11', 'The interval occurs when the first player or pair reaches 11 points.'),
('mobile legends', 'Battle Spells', 'The "Purify" spell can remove "Suppression" crowd control.', 'boolean', NULL, 'False', 'Suppression (like Franco''s Ultimate) is the only CC that cannot be removed by Purify.'),
('badminton', 'Double Hit', 'A player can hit the shuttle twice in one continuous stroke.', 'boolean', NULL, 'True', 'If the shuttle hits the frame and strings in one stroke, it is now legal under modern rules.'),
('mobile legends', 'Hero Skins', 'What is the highest rarity tier for skins found in the Magic Wheel?', 'text', NULL, 'Legend', 'Legend skins are the rarest and most expensive skins, often obtained via Magic Cores.'),
('badminton', 'Racket Material', 'Professional badminton rackets are mostly made of what material?', 'multiple_choice', '["Aluminum", "Steel", "Graphite/Carbon Fiber", "Wood"]', 'Graphite/Carbon Fiber', 'Modern rackets use high-modulus graphite for strength, flexibility, and lightness.'),
('mobile legends', 'Objectives', 'The "Turtle" buff provides a shield to the entire team.', 'boolean', NULL, 'False', 'While the gold/EXP is shared, only the person who slays the Turtle gets the shield/damage buff.'),
('badminton', 'Faults', 'Touching the net with your racket while the shuttle is in play is a fault.', 'boolean', NULL, 'True', 'Any part of the player or their racket touching the net results in a loss of the rally.'),
('mobile legends', 'Item Mechanics', 'Which item provides "True Damage" on basic attacks after using a skill?', 'multiple_choice', '["Endless Battle", "Blade of Despair", "War Axe", "Hunter Strike"]', 'Endless Battle', 'The "Divine Justice" passive makes Endless Battle essential for physical burst heroes.'),
('badminton', 'History', 'Badminton was once called "Poona" in India.', 'boolean', NULL, 'True', 'British officers brought the game back from Pune, India, where it was known as Poona.'),
('mobile legends', 'Hero Passives', 'Which hero gains "Stars" to increase her ultimate damage?', 'text', NULL, 'Chang''e', 'Chang''e’s mechanics revolve around her Crescent Moon and stacking damage for her Meteor Shower.'),
('badminton', 'Service Direction', 'In doubles, the serve must always be hit diagonally.', 'boolean', NULL, 'True', 'All legal serves in badminton must travel cross-court to the diagonal service area.'),
('mobile legends', 'Gameplay', 'What is the term for a team killing all five enemies at once?', 'text', NULL, 'Wiped Out', 'When every member of the opposing team is dead, the game announces "Wiped Out!".'),
('badminton', 'Technique', 'What is the name of the vertical jump used to hit a powerful smash?', 'multiple_choice', '["China Jump", "Scissors Kick", "Leap Step", "Split Step"]', 'Scissors Kick', 'The scissors kick is the footwork used in the air during a jump smash to maintain balance.'),
('mobile legends', 'Item Counters', 'Which item is the best counter to high Magic Burst damage (e.g., Eudora)?', 'multiple_choice', '["Radiant Armor", "Athena''s Shield", "Oracle", "Cursed Helmet"]', 'Athena''s Shield', 'Athena''s Shield provides a massive magic reduction shield when taking magic damage.'),
('badminton', 'Scoring', 'In the third game, players change ends when the score hits 11.', 'boolean', NULL, 'True', 'To ensure fairness in lighting or wind, players swap sides mid-way through the final set.'),
('mobile legends', 'Hero Passive', 'Which hero can "come back as an egg" after dying?', 'text', NULL, 'Diggie', 'Diggie’s passive allows him to move around as an egg and respawn at his current location.'),
('badminton', 'Famous Tournaments', 'The All England Open is the oldest badminton tournament in the world.', 'boolean', NULL, 'True', 'It was first held in 1899 and remains one of the most prestigious titles.'),
('mobile legends', 'Tower Shield', 'Turret shields disappear after how many minutes?', 'text', NULL, '5', 'The gold-granting shields on outer turrets expire at the 5-minute mark.'),
('badminton', 'Weight Rating', 'A 3U racket is lighter than a 4U racket.', 'boolean', NULL, 'False', 'In the "U" system, a lower number means a heavier racket (3U is approx 85-89g, 4U is 80-84g).'),
('mobile legends', 'Jungling', 'The "Blue Buff" reduces cooldowns and mana/energy consumption.', 'boolean', NULL, 'True', 'The Blue Buff (Thunder Fenrir) is vital for mana-hungry mages and energy-hungry assassins.'),
